mapper.select:
SELECT u.id AS id, u.public_id::text AS publicKey, COALESCE(u.user_type, 0) AS userType, COALESCE(u.first_name, '') AS firstName, COALESCE(u.last_name, '') AS lastName, COALESCE(u.username, '') AS username, COALESCE(u.email, '') AS email, COALESCE(u.telephone, '') AS telephone, COALESCE(TO_CHAR(u.expire_date, 'YYYY-MM-DD'), '') AS expireDate, u.created_by AS createdById, COALESCE( MAX( COALESCE( NULLIF(TRIM(CONCAT(COALESCE(uc.first_name, ''), ' ', COALESCE(uc.last_name, ''))), ''), uc.username ) ), '' ) AS createdBy, COALESCE(TO_CHAR(COALESCE(u.created_at, u.created), 'YYYY-MM-DD HH24:MI:SS'), '') AS created, u.modified_by AS modifiedById, COALESCE( MAX( COALESCE( NULLIF(TRIM(CONCAT(COALESCE(um.first_name, ''), ' ', COALESCE(um.last_name, ''))), ''), um.username ) ), '' ) AS modifiedBy, COALESCE(TO_CHAR(COALESCE(u.modified_at, u.modified), 'YYYY-MM-DD HH24:MI:SS'), '') AS modified, COALESCE(STRING_AGG(DISTINCT h.name, ', '), '') AS hospitalName FROM users u LEFT JOIN user_hospitals uh ON uh.user_id = u.id AND uh.is_active = 1 LEFT JOIN hospitals h ON h.id = uh.hospital_id AND h.is_active = 1 LEFT JOIN users uc ON uc.id = u.created_by LEFT JOIN users um ON um.id = u.modified_by WHERE u.is_active = 1
AND uh.hospital_id = #{hospitalId}
AND ( u.username ILIKE '%' || #{searchText} || '%' OR u.telephone ILIKE '%' || #{searchText} || '%' OR u.email ILIKE '%' || #{searchText} || '%' OR u.first_name ILIKE '%' || #{searchText} || '%' OR u.last_name ILIKE '%' || #{searchText} || '%' OR h.name ILIKE '%' || #{searchText} || '%' )
GROUP BY u.id, u.user_type, u.first_name, u.last_name, u.username, u.email, u.telephone, u.expire_date, u.created_by, u.created_at, u.created, u.modified_by, u.modified_at, u.modified
ORDER BY
${orderBy}
u.id DESC
LIMIT #{rowsPerPage} OFFSET #{page}

SELECT COUNT(DISTINCT u.id) FROM users u LEFT JOIN user_hospitals uh ON uh.user_id = u.id AND uh.is_active = 1 LEFT JOIN hospitals h ON h.id = uh.hospital_id AND h.is_active = 1 WHERE u.is_active = 1
AND uh.hospital_id = #{hospitalId}
AND ( u.username ILIKE '%' || #{searchText} || '%' OR u.telephone ILIKE '%' || #{searchText} || '%' OR u.email ILIKE '%' || #{searchText} || '%' OR u.first_name ILIKE '%' || #{searchText} || '%' OR u.last_name ILIKE '%' || #{searchText} || '%' OR h.name ILIKE '%' || #{searchText} || '%' )

SELECT COUNT(id)
FROM users
WHERE is_active = 1 AND username = #{username}

SELECT COUNT(id)
FROM users
WHERE is_active = 1
  AND username = #{username}
  AND id != #{id}

SELECT COUNT(id)
FROM users
WHERE is_active = 1 AND email = #{email}

mapper.update:
UPDATE users
SET
    password = #{password}
WHERE id = #{id};

mapper.select:
SELECT u.id AS value, u.public_id::text AS "publicKey", TRIM(CONCAT(COALESCE(u.first_name, ''), ' ', COALESCE(u.last_name, ''), CASE WHEN COALESCE(u.username, '') = '' THEN '' ELSE ' (' || u.username || ')' END)) AS label FROM users u JOIN user_hospitals uh ON uh.user_id = u.id WHERE u.is_active = 1 AND uh.is_active = 1 AND uh.hospital_id = #{hospitalId}
AND ( u.username ILIKE CONCAT('%', #{filter.searchText}, '%') OR u.first_name ILIKE CONCAT('%', #{filter.searchText}, '%') OR u.last_name ILIKE CONCAT('%', #{filter.searchText}, '%') )
ORDER BY u.id DESC
LIMIT #{filter.rowsPerPage} OFFSET #{filter.page}
